    color: #fff;
    font-size: 12px;
    font-weight: 700;
    cursor: pointer;
    font-family: inherit;
    width: calc(100% - 24px);
}

.rg-switch:hover {
    background: linear-gradient(90deg, #1648c2, #5a7fd9);
}

.rg-details {
    padding: 12px 14px;
    font-size: 11px;
    color: #666;
}

.rg-details-item {
    padding: 6px 0;
    border-bottom: 1px solid #f0f0f0;
}

.rg-details-label {
    font-weight: 600;
    color: #0a1628;
}

/* ============================================
   FLOATING AGENT BUTTON
   ============================================ */

.agent-fab {
    position: fixed;
    bottom: 28px;
    right: 28px;
    width: 54px;
    height: 54px;
    border-radius: 50%;
    background: linear-gradient(135deg, #7b2ff7, #b44cff);
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 22px;
    box-shadow: 0 4px 20px rgba(123, 47, 247, 0.4);
    z-index: 100;
    transition: transform 0.2s, box-shadow 0.2s;
}

.agent-fab:hover {
    transform: scale(1.08);
    box-shadow: 0 6px 28px rgba(123, 47, 247, 0.55);
}

.agent-fab-label {
    position: fixed;
    bottom: 34px;
    right: 88px;
    background: rgba(30, 30, 40, 0.85);
    color: #fff;
