    // 상단 배지 업데이트
    document.getElementById('user-badge').textContent = `${currentCustomer.avatar} ${currentCustomer.name}`;
}

function updateBannerUI() {
    if (currentCustomer.isGuest) {
        document.getElementById('banner-title').textContent =
            '지금 바로 시작하세요, 나만의 맞춤 신차';
        document.getElementById('banner-desc').textContent =
            '로그인 시 AI 기반 개인 맞춤 추천을 경험할 수 있습니다. 지금은 인기 차량 정보를 확인해 보세요.';
        document.getElementById('rec-title').textContent = '인기 자동차';
    } else {
        document.getElementById('banner-title').textContent =
            `${currentCustomer.name}님을 위한 맞춤 추천`;
        document.getElementById('banner-desc').textContent =
            `당신의 성향과 신용점수에 맞는 자동차가 추천되었습니다. ${currentCustomer.expectedFeature}를 중심으로 선별되었습니다.`;
        document.getElementById('rec-title').textContent =
            `${currentCustomer.name}님을 위한 추천 자동차`;
    }
}

// ============================================
// 상품 추천 렌더링
// ============================================

function renderRecommendedProducts() {
    if (currentCustomer.isGuest) {
        // 비회원: 인기차량 (상위 4개)
        filteredProducts = allProducts.slice(0, 4);
    } else {
        // 회원: 성향에 맞는 추천
        filteredProducts = getRecommendedProducts(currentCustomer);
    }

    displayProducts(filteredProducts);
}

function getRecommendedProducts(customer) {
    // 추천 점수 계산
    let scored = allProducts.map(product => {
        let score = 0;
        let matchCount = 0;

        // 고객의 선호도와 상품의 가중치 비교
        for (let key in customer.preferences) {
            if (product.weights && product.weights[key]) {
                // 공통 항목이 높을수록 높은 점수
                const customerPref = customer.preferences[key];
                const productWeight = product.weights[key];
                score += (customerPref * productWeight) / 10;
                matchCount++;
            }
        }

        score = matchCount > 0 ? score / matchCount : 0;

        // 차종 일치 보너스
        if (customer.preferredCarType !== '전체' && product.category === customer.preferredCarType) {
            score += 5;
        }

        return {
            ...product,
            recommendScore: Math.round(score * 10) / 10
        };
    });

    // 높은 점수순으로 정렬
    return scored.sort((a, b) => b.recommendScore - a.recommendScore);
}

function displayProducts(products) {
    const grid = document.getElementById('products-grid');

    grid.innerHTML = products.map(product => {
        let tag = '';
        if (product.tags && product.tags.length > 0) {
            const tagClass = product.tags[0] === '환경친화' ? 'tag-i' :
                            product.tags[0] === '럭셔리' ? 'tag-k' : 'tag-h';
            tag = `<span class="pc-tag ${tagClass}">${product.tags[0]}</span>`;
        }

        return `
            <div class="prod-card">
                <div class="pc-img">
                    <div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;color:#666;font-size:12px;">
                        🚗
                    </div>
                    ${tag}
                    <div class="pc-btns">
                        <button class="pc-btn" onclick="viewDetails('${product.id}')">상세</button>
                        <button class="pc-btn" onclick="selectProduct('${product.id}')">선택</button>
                    </div>
                </div>
                <div class="pc-info">
                    <div class="pc-brand">${product.brand}</div>
                    <div class="pc-name">${product.model}</div>
                    <div class="pc-spec">${product.category}</div>
                    <div class="pc-price">${formatPrice(product.price)}</div>
                    <div style="font-size:10px;color:#1a56db;margin-top:5px;font-weight:700;">
                        ${product.recommendScore ? '★ ' + product.recommendScore + '점' : '인기'}
                    </div>
                </div>
            </div>
        `;
    }).join('');
}

// ============================================
// 사용자 액션
// ============================================

function switchCustomer() {
    showCustomerSelection();
}

function viewDetails(productId) {
    const product = allProducts.find(p => p.id === productId);
    if (product) {
        alert(`${product.brand} ${product.model}\n\n가격: ${formatPrice(product.price)}\n엔진: ${product.engine}\n특징: ${product.features.join(', ')}`);
    }
}

function selectProduct(productId) {
    const product = allProducts.find(p => p.id === productId);
    if (product) {
        alert(`${product.brand} ${product.model}이(가) 선택되었습니다.\n\n금융상품 안내 페이지로 이동합니다.`);
        // TODO: 금융상품 페이지로 이동
    }
}

function openChat() {
    document.getElementById('chat-panel').classList.add('open');
}

function closeChat() {
    document.getElementById('chat-panel').classList.remove('open');
}

function scrollToProducts() {
    document.getElementById('products-grid').scrollIntoView({ behavior: 'smooth' });
}

// ============================================
// 유틸리티
// ============================================

function formatPrice(price) {
    if (price >= 10000000) {
        return (price / 10000000).toFixed(1) + '천만원';
    } else if (price >= 1000000) {
        return Math.round(price / 1000000) + '백만원';
    }
    return price.toLocaleString() + '원';
}

