// ============================================
// 상태 관리
// ============================================

var chatOpened = false;
var scenarioRunning = false;

// ============================================
// 초기화
// ============================================

window.addEventListener('DOMContentLoaded', function() {
  // 검색 시스템 초기화
  const initResult = initSearch();
  if (initResult) {
    console.log('✅ 검색 시스템 초기화 완료');
  }

  // 검색 입력 이벤트
  const searchInput = document.getElementById('search-input');
  if (searchInput) {
    searchInput.addEventListener('input', function(e) {
      handleSearchInput(e.target.value);
    });
  }

  console.log('non_member.js 로드 완료');
});

// ============================================
// 채팅 UI 핸들러
// ============================================

/**
 * 채팅 패널 열기
 */
function openChat() {
  var chatPanel = document.getElementById("chatPanel");
  var backdrop = document.getElementById("backdrop");

  if (!chatPanel.classList.contains("open")) {
    chatPanel.classList.add("open");
    backdrop.classList.add("on");
  }

  if (!chatOpened) {
    chatOpened = true;
    playScenario();
  }
}

/**
 * 채팅 패널 닫기
 */
function closeChat() {
  var chatPanel = document.getElementById("chatPanel");
  var backdrop = document.getElementById("backdrop");

  chatPanel.classList.remove("open");
  backdrop.classList.remove("on");
}

// backdrop 클릭 시 채팅 닫기
document.addEventListener('DOMContentLoaded', function() {
  var backdrop = document.getElementById("backdrop");
  if (backdrop) {
    backdrop.addEventListener('click', closeChat);
  }
});

// ============================================
// 시나리오 실행
// ============================================

/**
 * 시나리오 자동 재생
 */
function playScenario() {
  if (scenarioRunning) return;
  scenarioRunning = true;

  var body = document.querySelector(".cl-body");
  var progressBars = document.querySelectorAll(".prog-step");
  var progressLabel = document.querySelector(".prog-label");

  for (var i = 0; i < SCENARIO.length; i++) {
    var step = SCENARIO[i];

    (function(index, stepData) {
      var delay = stepData.delay || 0;

      setTimeout(function() {
        if (stepData.type === "agent") {
          addBotMessage(body, stepData.text);
        } else if (stepData.type === "user") {
          addUserMessage(body, stepData.text);
        } else if (stepData.type === "progress") {
          updateProgressBar(progressBars, stepData.index, progressLabel);
        } else if (stepData.type === "summary") {
          addSummaryBox(body, stepData.items);
        } else if (stepData.type === "rec") {
          addRecommendations(body, stepData.cars);
        } else if (stepData.type === "typing") {
          addTypingIndicator(body);
          setTimeout(function() {
            removeTypingIndicator(body);
          }, 1500);
        }
      }, delay);
    })(i, step);
  }
}

// ============================================
// 메시지 렌더링 함수들
// ============================================

/**
 * 봇 메시지 추가
 */
function addBotMessage(container, text) {
  var msg = document.createElement('div');
  msg.className = 'msg msg-anim';
  msg.innerHTML = '<div class="m-av av-bot">🤖</div>' +
                  '<div class="msg-r">' +
                    '<div class="bubble b-bot">' + text.replace(/\n/g, '<br>') + '</div>' +
                    '<div class="m-time">' + new Date().toLocaleTimeString('ko-KR', {hour: '2-digit', minute:'2-digit'}) + '</div>' +
                  '</div>';
  container.appendChild(msg);
  container.scrollTop = container.scrollHeight;
}

/**
 * 사용자 메시지 추가
 */
function addUserMessage(container, text) {
  var msg = document.createElement('div');
  msg.className = 'msg msg-user msg-anim';
  msg.innerHTML = '<div class="m-av av-usr">👤</div>' +
                  '<div class="msg-r">' +
                    '<div class="bubble b-usr">' + text + '</div>' +
                    '<div class="m-time">' + new Date().toLocaleTimeString('ko-KR', {hour: '2-digit', minute:'2-digit'}) + '</div>' +
                  '</div>';
  container.appendChild(msg);
  container.scrollTop = container.scrollHeight;
}

/**
 * 프로그레스 바 업데이트
 */
function updateProgressBar(bars, index, label) {
  for (var i = 0; i < bars.length; i++) {
    bars[i].classList.remove('active', 'done');
    if (i < index) {
      bars[i].classList.add('done');
    } else if (i === index) {
      bars[i].classList.add('active');
    }
  }
}

/**
 * 조건 요약 박스 추가
 */
function addSummaryBox(container, items) {
  var summary = document.createElement('div');
  summary.className = 'cond-summary';

  var title = '<div class="cs-title">📋 분석된 고객 조건</div>';
  var rows = items.map(function(item) {
    return '<div class="cond-row">' +
           '<div class="cond-ico">' + item.ico + '</div>' +
           '<div><strong>' + item.label + ':</strong> <span class="cond-val">' + item.val + '</span></div>' +
           '</div>';
  }).join('');

  summary.innerHTML = title + rows;

  var wrapper = document.createElement('div');
  wrapper.className = 'msg msg-anim';
  wrapper.style.marginTop = '8px';
  wrapper.appendChild(summary);

  container.appendChild(wrapper);
  container.scrollTop = container.scrollHeight;
}

/**
 * 추천 차량 카드 추가
 */
function addRecommendations(container, carKeys) {
  var wrapper = document.createElement('div');
  wrapper.className = 'msg msg-anim';

  var cardsHtml = '<div class="rec-wrap">';

  carKeys.forEach(function(carKey) {
    var car = getCarFromAllResults(carKey);
    if (car) {
      cardsHtml += '<div class="rc">' +
                   '<div class="rc-img"><img src="' + CAR_IMGS[carKey] + '" alt="' + car.name + '"></div>' +
                   '<div class="rc-info">' +
                   '<div class="rc-brand">' + car.brand + '</div>' +
                   '<div class="rc-name">' + car.name + '</div>' +
                   '<div class="rc-spec">' + car.spec + '</div>' +
                   '<div class="rc-price">' + car.price + '</div>' +
                   '<button class="rc-btn" onclick="selectProduct(\'' + carKey + '\')">선택하기</button>' +
                   '</div></div>';
    }
  });

  cardsHtml += '</div>';

  wrapper.innerHTML = '<div class="m-av av-bot">🤖</div>' +
                      '<div class="msg-r">' +
