15	
16	.header{background:#fff;border-bottom:1px solid #e8e8e8;padding:10px 24px;display:flex;align-items:center;}
17	.logo{font-size:26px;font-weight:900;letter-spacing:-0.04em;color:#0a1628;margin-right:22px;}
