 */
function setTab(element, tabName) {
  // 기존 활성 탭 제거
  const tabs = document.querySelectorAll('.jtab');
  tabs.forEach(t => t.classList.remove('on'));

  // 새 탭 활성화
  element.classList.add('on');

  // 고객 여정 리스트 업데이트
  updateJourneyList(tabName);
}

