function playScenario() {
  var t = 0;
  for (var i = 0; i < SCENARIO.length; i++) {
    var step = SCENARIO[i];
    t += step.delay;

    (function(s, fireAt) {
      setTimeout(function() { playStep(s); }, fireAt);
    })(step, t);

    // agent 타입은 타이핑 애니메이션 시간만큼 t를 추가해서
    // 다음 이벤트가 반드시 메시지 출력 이후에 시작되게 함
    if (step.type === "agent") {
      t += 500 + step.text.length * 20;
    }
    // summary도 마찬가지로 렌더 시간 확보
    if (step.type === "summary") {
      t += 400;
    }
  }
}

function playStep(step) {
  if (step.type === "agent") {
    var tid = showTyping();
    var dur = 500 + step.text.length * 20;
    (function(id, txt) {
      setTimeout(function() { removeTyping(id); appendAgent(txt); }, dur);
    })(tid, step.text);

  } else if (step.type === "user") {
    appendUser(step.text);

  } else if (step.type === "progress") {
    updateProgress(step.index);

  } else if (step.type === "summary") {
    var rows = step.items.map(function(it) {
      return '<div class="cond-row"><span class="cond-ico">' + it.ico + '</span>' +
             '<span style="color:#6b7280;font-size:11px;">' + it.label + '</span>' +
             '<span style="margin-left:auto;font-weight:700;color:#1a1a2e;font-size:11px;">' + it.val + '</span></div>';
    }).join("");
    appendAgentHTML(
      '<div class="cond-summary">' +
      '<div class="cs-title">📋 수집된 고객 조건</div>' +
      rows +
      '</div>'
    );

  } else if (step.type === "rec") {
    showRec(step.cars);
  }
}

function updateProgress(idx) {
  // 완료된 단계 색칠
  for (var i = 0; i < 5; i++) {
    var ps = document.getElementById("ps" + i);
    var pl = document.getElementById("pl" + i);
    if (i < idx) {
