// 프로그레스 바 업데이트
// ============================================

function updateProgress(idx) {
  for (var i = 0; i < 5; i++) {
    var ps = document.getElementById("ps" + i);
    var pl = document.getElementById("pl" + i);
    if (!ps || !pl) continue;

    if (i < idx) {
      ps.className = "prog-step done";
      pl.className = "";
    } else if (i === idx && idx < 5) {
      ps.className = "prog-step active";
      pl.className = "cur";
    } else {
      ps.className = "prog-step";
      pl.className = "";
    }
  }
}

