function playScenario() {
  var t = 0;

  for (var i = 0; i < SCENARIO.length; i++) {
    var step = SCENARIO[i];
    t += step.delay;

    (function(s, fireAt) {
      setTimeout(function() { playStep(s); }, fireAt);
    })(step, t);

    // agent 타입은 타이핑 인디케이터 표시 시간을 누적에 추가
