    ? 'linear-gradient(130deg,#0d1b4b,#1a3278 45%,#2563eb 80%,#5a8dee 100%)'
    : 'linear-gradient(130deg,#064e3b,#065f46 45%,#10b981 80%,#6ee7b7 100%)';

  section.innerHTML = `
    <div class="banner" style="background:${bannerGrad}">
