238	        <div class="j-tag">${item.tag}</div>
239	        <div class="j-name">${item.name}</div>
240	        <div class="j-cat">${item.cat}</div>
241	      </div>
242	    </div>
243	  `).join('');
244	}
245	
246	// ============================================
247	// 사용자 선택 및 조작
248	// ============================================
249	
250	/**
251	 * A 사용자 선택
252	 */
253	function onSelectA(value) {
254	  currentUser = value;
255	  if (value === 'C') {
256	    showGuestView();
257	  } else {
258	    showMemberView();
259	    renderMain();
260	  }
261	}
262	
263	/**
264	 * B 사용자 선택
265	 */
266	function onSelectB(value) {
267	  compareUser = value;
268	}
269	
270	/**
271	 * 적용 버튼
272	 */
273	function apply() {
274	  if (compareUser !== 'none') {
275	    alert(`${currentUser}사용자와 ${compareUser}사용자를 비교하는 기능은 추후 추가됩니다.`);
276	  }
277	  renderMain();
278	}
279	
280	/**
281	 * 이전 사용자
282	 */
283	function prevUser() {
284	  currentUser = currentUser === 'A' ? 'B' : 'A';
285	  renderMain();
286	}
287	
288	/**
289	 * 다음 사용자
290	 */
291	function nextUser() {
292	  currentUser = currentUser === 'A' ? 'B' : 'A';
293	  renderMain();
294	}
295	
296	/**
297	 * 새로고침
298	 */
299	function refresh() {
300	  renderMain();
301	  console.log(`${currentUser}사용자 정보 새로고침됨`);
302	}
303	
304	// ============================================
305	// 비회원/회원 뷰 전환
306	// ============================================
307	
308	/**
309	 * 회원 뷰 표시
310	 */
311	function showMemberView() {
312	  const memberSidebar = document.getElementById('memberSidebar');
313	  const guestSidebar = document.getElementById('guestSidebar');
314	  if (memberSidebar) memberSidebar.style.display = '';
315	  if (guestSidebar) guestSidebar.style.display = 'none';
316	}
317	
318	/**
319	 * 비회원 뷰 표시
320	 */
321	function showGuestView() {
322	  const memberSidebar = document.getElementById('memberSidebar');
323	  const guestSidebar = document.getElementById('guestSidebar');
324	  if (memberSidebar) memberSidebar.style.display = 'none';
325	  if (guestSidebar) guestSidebar.style.display = 'flex';
326	  renderGuestMain();
327	}
328	
329	/**
330	 * 비회원 메인 콘텐츠 렌더링
331	 */
332	function renderGuestMain() {
333	  const section = document.getElementById('recommended-section');
334	  if (!section) return;
335	
336	  // 비회원용 배너 + 인기차 목록
337	  const html = `
338	    <div class="banner" onclick="openChat()" style="background: linear-gradient(120deg,#1e3a5f,#2563eb 60%,#60a5fa); cursor:pointer;">
339	      <div>
340	        <h2>나만의 맞춤 신차,<br>AI가 찾아드립니다</h2>
341	        <p>몇 가지 질문으로 고객님께 딱 맞는<br>차량을 바로 추천해드려요.</p>
342	        <span class="banner-cta">✨ AI 추천 받기 →</span>
343	      </div>
344	      <div class="banner-deco">🤖</div>
345	      <div class="banner-hint">👆 클릭하면 AI 상담을 시작합니다</div>
346	    </div>
347	    <div class="sec-hdr">
348	      <span style="font-size:15px">✨</span>
349	      <h3>요즘 주목 받는 신차 안내</h3>
350	    </div>
351	    <div class="prod-grid" id="popularGrid"></div>
352	  `;
353	
354	  section.innerHTML = html;
355	  renderPopularCars();
356	
357	  // 검색 결과 숨기기
358	  const resultsContainer = document.getElementById('search-results-container');
359	  if (resultsContainer) {
360	    resultsContainer.style.display = 'none';
361	  }
362	}
363	
364	/**
365	 * 인기 차량 목록 렌더링
366	 */
367	function renderPopularCars() {
368	  const grid = document.getElementById('popularGrid');
369	  if (!grid || typeof SEARCH_RESULTS === 'undefined') return;
370	
371	  // SEARCH_RESULTS의 모든 차량을 모아서 표시
372	  const allCars = [];
373	  for (const resultId in SEARCH_RESULTS) {
374	    SEARCH_RESULTS[resultId].cars.forEach(car => {
375	      // 중복 제거
376	      if (!allCars.find(c => c.img === car.img)) {
377	        allCars.push(car);
378	      }
379	    });
380	  }
381	
382	  grid.innerHTML = allCars.slice(0, 8).map(car => `
383	    <div class="prod-card">
384	      <div class="pc-img">
385	        <img src="${CAR_IMGS[car.img]}" alt="${car.name}" style="max-width:100%; max-height:100%; object-fit:contain;">
386	        <span class="pc-tag ${car.tagC}">${car.tag}</span>
387	        <div class="pc-btns">
388	          <button class="pc-btn" onclick="viewDetails('${car.img}')">상세</button>
389	          <button class="pc-btn" onclick="selectProduct('${car.img}')">선택</button>
390	        </div>
391	      </div>
392	      <div class="pc-info">
393	        <div class="pc-brand">${car.brand}</div>
394	        <div class="pc-name">${car.name}</div>
395	        <div class="pc-spec">${car.spec}</div>
396	        <div class="pc-price">${car.price}</div>
397	      </div>
398	    </div>
399	  `).join('');
400	}
401	
402	// ============================================
403	// 로고 클릭 핸들러
404	// ============================================
405	
406	/**
407	 * 로고 클릭 = 검색 초기화 (홈으로)
408	 */
409	function logoHome() {
410	  const input = document.getElementById('search-input');
411	  if (input) input.value = '';
412	  showDefaultResults();
413	}
414	
415	/**
416	 * 탭 전환 (고객 여정)
417	 */
418	function setTab(element, tabName) {
419	  // 기존 활성 탭 제거
420	  const tabs = document.querySelectorAll('.jtab');
421	  tabs.forEach(t => t.classList.remove('on'));
422	
423	  // 새 탭 활성화
424	  element.classList.add('on');
425	
426	  // 고객 여정 리스트 업데이트
427	  updateJourneyList(tabName);
428	}
429	
430	// ============================================
431	// 검색 기능 통합
432	// ============================================
433	
434	/**
435	 * 전체 결과셋에서 차량 찾기 (renderMain용)
436	 */
437	function getCarFromAllResults(carKey) {
438	  // SEARCH_RESULTS의 모든 결과셋에서 찾기
439	  if (typeof SEARCH_RESULTS !== 'undefined') {
440	    for (const resultId in SEARCH_RESULTS) {
441	      const result = SEARCH_RESULTS[resultId];
442	      const car = result.cars.find(c => c.img === carKey);
443	      if (car) return car;
444	    }
445	  }
446	  return null;
447	}
448	
449	// ============================================
450	// 차량 선택 / 상세보기 (common.js 함수 오버라이드)
451	// ============================================
452	
453	function selectProduct(imgKey) {
454	  alert(`${imgKey.toUpperCase()} 차량이 선택되었습니다.\n금융상품 안내로 이동합니다.`);
455	}
456	
457	function viewDetails(imgKey) {
458	  const carInfo = {
459	    g80: 'GENESIS G80 3.5T AWD 스포츠패키지 - 380마력',
460	    bmw5: 'BMW 5시리즈 530i xDrive M스포츠 - 252마력',
461	    k8: 'KIA K8 3.5 GDI 시그니처 - 300마력',
462	    grandeur: 'HYUNDAI 그랜저 캘리그래피 3.5 GDI - 304마력',
463	    sorento: 'KIA 쏘렌토 하이브리드 시그니처 - 7인승, 연비 16.0km/L',
464	    tucson: 'HYUNDAI 투싼 하이브리드 인스퍼레이션 - 연비 15.6km/L',
465	    nx350h: 'LEXUS NX 350h F SPORT - 연비 14.6km/L',
466	    santafe: 'HYUNDAI 싼타페 하이브리드 캘리그래피 - 7인승, 연비 14.2km/L'
467	  };
468	  alert(carInfo[imgKey] || '차량 정보를 찾을 수 없습니다.');
469	}
470	
471	// ============================================
472	// 채팅 패널 헬퍼 함수
473	// ============================================
474	
475	/**
476	 * 견적 차량 리스트 초기화
477	 */
478	function resetCr() {
479	  const crList = document.getElementById('crList');
480	  if (crList) {
481	    crList.innerHTML = `
482	      <div class="cr-empty-wrap">
483	        <div class="cr-empty-ico">🚗</div>
484	        <div class="cr-empty-txt">AI 상담 후<br>관심 차량이 표시됩니다</div>
