/**
 * 적용 버튼
 */
function apply() {
  if (currentUser === 'C') {
    showGuestView();
    return;
  }
  if (compareUser !== 'none' && compareUser !== currentUser) {
    showMemberView();
    renderCompareMain();
  } else {
    showMemberView();
    renderMain();
  }
}

/**
 * 비교 모드 메인 렌더링 (좌우 2열 sec-row)
 */
function renderCompareMain() {
  const section = document.getElementById('recommended-section');
  if (!section) return;

  const dA = DATA[currentUser];
  const bannerGrad = currentUser === 'A'
    ? 'linear-gradient(130deg,#0d1b4b 0%,#1a3278 45%,#2563eb 80%,#5a8dee 100%)'
    : 'linear-gradient(130deg,#0a4d2c 0%,#16a34a 45%,#22c55e 80%,#86efac 100%)';

  section.innerHTML = `
    <div class="banner" style="background:${bannerGrad}">
      <div class="banner-txt">
        <h2>${dA.bannerText.title}</h2>
        <p>${dA.bannerText.subtitle}</p>
        <span class="banner-badge">${dA.bannerText.badge}</span>
      </div>
      <div class="banner-deco">🚗</div>
    </div>
    <div class="sec-row">
      ${renderUserBlock(currentUser)}
      ${renderUserBlock(compareUser)}
    </div>
  `;

  // 사이드바 업데이트
