}

/**
 * 적용 버튼
 */
function apply() {
  if (compareUser !== 'none') {
    alert(`${currentUser}사용자와 ${compareUser}사용자를 비교하는 기능은 추후 추가됩니다.`);
  }
  renderMain();
}

/**
 * 이전 사용자
 */
function prevUser() {
  currentUser = currentUser === 'A' ? 'B' : 'A';
  renderMain();
}

