      ${resultData.cars.map(car => `
        <div class="car-card" onclick="viewDetails('${car.img}')">
          <div class="car-img">
            <img src="${CAR_IMGS[car.img]}" alt="${car.name}" style="max-width:100%; max-height:100%; object-fit:contain;">
            <span class="img-tag ${car.tagC}">${car.tag}</span>
            <div class="img-btns">
              <button class="ib" onclick="viewDetails('${car.img}'); event.stopPropagation();">상세</button>
              <button class="ib" onclick="selectProduct('${car.img}'); event.stopPropagation();">선택</button>
            </div>
          </div>
          <div class="car-info">
            <div class="car-brand">${car.brand}</div>
            <div class="car-name">${car.name}</div>
            <div class="car-spec">${car.spec}</div>
            <div class="price-row"><span class="price">${car.price}</span></div>
            <div class="price-sub">${car.sub}</div>
            <div style="font-size:10px;color:#1a56db;margin-top:5px;font-weight:700;">★ ${car.highlight}</div>
          </div>
        </div>
      `).join('')}
    </div>
  `;
  return section;
}

/**
 * 비교 모드 검색결과 섹션 (좌우 sec-row 2열)
 */
function createCompareSearchSection(dataA, dataB) {
  const section = document.createElement('div');
  section.className = 'search-result-section';
  const blockA = dataA ? renderSearchBlock(dataA, currentUser) : '<div style="color:#ccc;font-size:12px;padding:20px;text-align:center;">결과 없음</div>';
  const blockB = dataB ? renderSearchBlock(dataB, compareUser) : '<div style="color:#ccc;font-size:12px;padding:20px;text-align:center;">결과 없음</div>';
  section.innerHTML = `<div class="sec-row">${blockA}${blockB}</div>`;
  return section;
}

/**
 * 비교 모드 개별 사용자 블록 HTML
 */
function renderSearchBlock(resultData, userKey) {
  const badgeC = userKey === 'A' ? 'badge-a' : 'badge-b';
  const nameC  = userKey === 'A' ? 'name-a'  : 'name-b';
  const userName = (typeof DATA !== 'undefined' && DATA[userKey]) ? DATA[userKey].name : (userKey + '사용자');
  const priceColor = userKey === 'A' ? '#1a56db' : '#28c76f';

  const cards = resultData.cars.map(car => `
    <div class="car-card" onclick="viewDetails('${car.img}')">
      <div class="car-img">
        <img src="${CAR_IMGS[car.img]}" alt="${car.brand}" style="max-width:100%; max-height:100%; object-fit:contain;">
        <span class="img-tag ${car.tagC}">${car.tag}</span>
        <div class="img-btns">
          <button class="ib" onclick="viewDetails('${car.img}');event.stopPropagation();">상세</button>
          <button class="ib" onclick="selectProduct('${car.img}');event.stopPropagation();">선택</button>
        </div>
      </div>
      <div class="car-info">
        <div class="car-brand">${car.brand}</div>
        <div class="car-name">${car.name}</div>
        <div class="car-spec">${car.spec}</div>
        <div class="price-row"><span class="price" style="color:${priceColor}">${car.price}</span></div>
        <div class="price-sub">${car.sub}</div>
        <div style="font-size:10px;color:${priceColor};margin-top:5px;font-weight:700;">★ ${car.highlight}</div>
      </div>
    </div>
  `).join('');

  return `<div>
    <div class="sec-label">
      <span class="badge ${badgeC}">AI 추천</span>
      <span class="sec-title"><span class="${nameC}">${userName}</span>님 · ${resultData.description}</span>
    </div>
    <div class="car-grid">${cards}</div>
  </div>`;
}

/**
 * 검색 결과 없음 표시
 */
function showNoResults(keywords) {
  const resultsContainer = document.getElementById('search-results-container');

  if (!resultsContainer) return;

  const recommendedSection = document.getElementById('recommended-section');
  if (recommendedSection) {
    recommendedSection.style.display = 'none';
  }

  resultsContainer.innerHTML = `
    <div class="search-no-result">
      <div class="no-result-icon">🔍</div>
      <div class="no-result-text">"${keywords.join(' ')}"에 맞는 검색 결과가 없습니다.</div>
      <div class="no-result-subtitle">다른 검색어를 시도해보세요.</div>
      <div class="search-suggestions">
        <div class="suggestion-title">추천 검색어:</div>
        <div class="suggestion-chips">
          ${searchQueries.map(q => `
            <div class="suggestion-chip" onclick="document.querySelector('#search-input').value='${q.label}'; handleSearchInput('${q.label}')">
              ${q.description}
            </div>
          `).join('')}
        </div>
      </div>
    </div>
  `;

  resultsContainer.style.display = 'block';
}

/**
 * 기본 상태로 복귀 (검색창 비움)
 */
function showDefaultResults() {
  const resultsContainer = document.getElementById('search-results-container');
  const recommendedSection = document.getElementById('recommended-section');

  if (resultsContainer) {
    resultsContainer.style.display = 'none';
  }

  if (recommendedSection) {
    recommendedSection.style.display = 'block';
  }
}

/**
 * 상품 선택 핸들러
 */
function selectProduct(imgKey) {
  alert(`${imgKey.toUpperCase()} 차량이 선택되었습니다.\n금융상품 안내로 이동합니다.`);
  // TODO: 금융상품 페이지로 이동
}

/**
 * 상품 상세 보기 핸들러
 */
function viewDetails(imgKey) {
  // 현재는 기본 alert (추후 모달로 변경 가능)
  const carInfo = {
    g80: 'GENESIS G80 3.5T AWD 스포츠패키지 - 380마력',
    bmw5: 'BMW 5시리즈 530i xDrive M스포츠 - 252마력',
    k8: 'KIA K8 3.5 GDI 시그니처 - 300마력',
    grandeur: 'HYUNDAI 그랜저 캘리그래피 3.5 GDI - 304마력',
    sorento: 'KIA 쏘렌토 하이브리드 시그니처 - 7인승, 연비 16.0km/L',
    tucson: 'HYUNDAI 투싼 하이브리드 인스퍼레이션 - 연비 15.6km/L',
    nx350h: 'LEXUS NX 350h F SPORT - 연비 14.6km/L',
    santafe: 'HYUNDAI 싼타페 하이브리드 캘리그래피 - 7인승, 연비 14.2km/L'
  };

  alert(carInfo[imgKey] || '차량 정보를 찾을 수 없습니다.');
}

